  "actor": {
    "pos": "noun",
    "en": {
      "def": "Someone who gets paid to pretend they are a pirate, a king, or a potato.",
      "sentence": "The actor forgot his lines and just stared at the camera like a confused goldfish."
    },
    "phonics": {
      "is_compound": false,
      "is_multisyllabic": true,
      "is_sight_word": false,
      "patterns": [
        "r_controlled",
        "multisyllable",
        "schwa"
      ],
      "primary_level": "multisyllabic",
      "scope_sequence": [
        "r_controlled",
        "multisyllable",
        "schwa"
      ],
      "syllables": 2,
      "syllable_parts": [
        "ac",
        "tor"
      ]
    },
    "es": {
      "def": "Alguien a quien se le paga por fingir que es un pirata, un rey o una papa.",
      "sentence": "El actor olvidó sus líneas y se quedó mirando a la cámara como un pez dorado confundido."
    },
    "zh": {
      "def": "一个拿钱假装自己是海盗、国王或土豆的人。",
      "sentence": "那个演员忘了台词，只是像条困惑的金鱼一样盯着摄像机。"
    },
    "ar": {
      "def": "شخص يتقاضى أجرًا ليتظاهر بأنه قرصان أو ملك أو حبة بطاطس.",
      "sentence": "نسي الممثل سطوره وحدق في الكاميرا مثل سمكة ذهبية مشوشة."
    },
    "vi": {
      "def": "Người được trả tiền để giả vờ làm cướp biển, nhà vua hoặc củ khoai tây.",
      "sentence": "Nam diễn viên quên lời thoại và cứ nhìn chằm chằm vào máy quay như một con cá vàng ngơ ngác."
    },
    "ko": {
      "def": "돈을 받고 해적, 왕, 감자인 척하는 사람.",
      "sentence": "배우는 대사도 잊어버린 채 어리둥절한 금붕어처럼 카메라를 응시했다."
    },
    "tl": {
      "def": "Tao na binabayaran para magkunwaring pirata, hari, o patatas.",
      "sentence": "Nakalimutan ng aktor ang linya niya at tumitig lang sa camera na parang litong goldfish."
    }
  },
