  "construct": {
    "pos": "noun",
    "en": {
      "def": "To build something huge out of small pieces, usually without reading the instructions.",
      "sentence": "We tried to construct a robot out of cardboard boxes, but it fell over and scared the cat."
    },
    "phonics": {
      "is_compound": false,
      "is_multisyllabic": true,
      "is_sight_word": false,
      "patterns": [
        "multisyllable",
        "prefix"
      ],
      "primary_level": "multisyllabic",
      "scope_sequence": [
        "multisyllable",
        "prefix"
      ],
      "syllables": 2,
      "syllable_parts": [
        "con",
        "struct"
      ]
    },
    "es": {
      "def": "Construir algo enorme a partir de piezas pequeñas, generalmente sin leer las instrucciones.",
      "sentence": "Intentamos construir un robot con cajas de cartón, pero se cayó y asustó al gato."
    },
    "zh": {
      "def": "用小零件建造巨大的东西，通常不看说明书。",
      "sentence": "我们试着用纸板箱造一个机器人，但它倒了，把猫吓了一跳。"
    },
    "ar": {
      "def": "لبناء شيء ضخم من قطع صغيرة، عادة دون قراءة التعليمات.",
      "sentence": "حاولنا صنع روبوت من الصناديق الكرتونية، لكنه سقط وأخاف القطة."
    },
    "vi": {
      "def": "Xây dựng thứ gì đó to lớn từ những mảnh nhỏ, thường là làm mà không thèm đọc hướng dẫn.",
      "sentence": "Chúng tôi cố dựng một con rô bốt bằng thùng các-tông, nhưng nó đổ ập xuống làm con mèo khiếp vía."
    },
    "ko": {
      "def": "일반적으로 설명서를 읽지 않고 작은 조각으로 거대한 것을 만들다.",
      "sentence": "우리는 판지 상자로 로봇을 만들려고 했지만 로봇이 넘어져서 고양이가 겁을 먹었습니다."
    },
    "tl": {
      "def": "Magtayo ng malaking bagay gamit ang maliliit na piyesa, madalas nang hindi nagbabasa ng instructions.",
      "sentence": "Sinubukan naming gumawa ng robot gamit ang mga karton, pero natumba ito at tinakot ang pusa."
    }
  },
