  "interrupt": {
    "pos": "noun",
    "en": {
      "def": "To burst into a conversation when nobody asked for your opinion.",
      "sentence": "It is rude to interrupt the teacher just to tell her that a squirrel is looking at you."
    },
    "phonics": {
      "is_compound": false,
      "is_multisyllabic": true,
      "is_sight_word": false,
      "patterns": [
        "r_controlled",
        "multisyllable",
        "prefix"
      ],
      "primary_level": "multisyllabic",
      "scope_sequence": [
        "r_controlled",
        "multisyllable",
        "prefix"
      ],
      "syllables": 3,
      "syllable_parts": [
        "in",
        "ter",
        "rupt"
      ]
    },
    "es": {
      "def": "Irrumpir en una conversación cuando nadie pidió tu opinión.",
      "sentence": "Es de mala educación interrumpir a la maestra solo para decirle que una ardilla te está mirando."
    },
    "zh": {
      "def": "当没人征求你的意见时，强行介入谈话。",
      "sentence": "仅仅为了告诉老师一只松鼠在看你就打断她是粗鲁的。"
    },
    "ar": {
      "def": "الدخول في محادثة عندما لا يطلب منك أحد رأيك.",
      "sentence": "من الوقاحة مقاطعة المعلمة فقط لإخبارها أن هناك سنجابًا ينظر إليك."
    },
    "vi": {
      "def": "Chen ngang vào cuộc trò chuyện khi không ai hỏi ý kiến bạn.",
      "sentence": "Thật bất lịch sự khi ngắt lời cô giáo chỉ để nói rằng có một con sóc đang nhìn bạn."
    },
    "ko": {
      "def": "아무도 당신의 의견을 묻지 않았을 때 대화를 시작합니다.",
      "sentence": "다람쥐가 당신을 보고 있다고 선생님에게 말하려고 방해하는 것은 무례한 행동입니다."
    },
    "tl": {
      "def": "Ang pagsingit sa usapan kahit wala namang humihingi ng opinyon mo.",
      "sentence": "Bastos mag-interrupt sa titser para lang sabihing may nakatingin sa'yong squirrel."
    }
  },
