  "preheat": {
    "pos": "noun",
    "en": {
      "def": "Waiting for the oven to get hot while you eat all the raw cookie dough.",
      "sentence": "I set the oven to preheat, got bored waiting, and ate half the cookies before they were baked."
    },
    "phonics": {
      "is_compound": true,
      "is_multisyllabic": true,
      "is_sight_word": false,
      "patterns": [
        "vowel_team",
        "multisyllable",
        "compound",
        "prefix"
      ],
      "primary_level": "multisyllabic",
      "scope_sequence": [
        "vowel_team",
        "multisyllable",
        "compound",
        "prefix"
      ],
      "syllables": 2,
      "syllable_parts": [
        "pre",
        "heat"
      ]
    },
    "es": {
      "def": "Esperar a que el horno se caliente mientras te comes toda la masa cruda de las galletas.",
      "sentence": "Puse el horno a precalentar, me aburrí esperando y me comí la mitad de las galletas antes de que se hornearan."
    },
    "zh": {
      "def": "在等烤箱变热的过程中，把生的曲奇面团都吃光了。",
      "sentence": "我设定了烤箱预热，等得不耐烦，在饼干烤好之前就吃掉了一半面团。"
    },
    "ar": {
      "def": "الانتظار حتى يسخن الفرن أثناء تناول كل عجينة البسكويت النيئة.",
      "sentence": "قمت بضبط الفرن على التسخين المسبق، وشعرت بالملل من الانتظار، وأكلت نصف قطع البسكويت قبل خبزها."
    },
    "vi": {
      "def": "Chờ lò nướng nóng lên trong khi bạn ăn hết chỗ bột bánh quy sống.",
      "sentence": "Tôi bật lò làm nóng trước, thấy chán khi phải chờ đợi, và ăn hết một nửa số bánh quy trước khi chúng được nướng."
    },
    "ko": {
      "def": "생 쿠키 반죽을 모두 먹는 동안 오븐이 뜨거워지기를 기다립니다.",
      "sentence": "나는 오븐을 예열하도록 설정하고 기다리기 지루해져서 쿠키가 구워지기 전에 절반을 먹었습니다."
    },
    "tl": {
      "def": "Ang paghihintay na uminit ang oven habang inuubos mo ang hilaw na cookie dough.",
      "sentence": "Sinet ko ang oven para mag-preheat, nabagot kakahintay, at kinain ang kalahati ng cookies bago pa maluto."
    }
  },
